// Access both nodes by name to avoid data merge issues
let attendance = [];
let technicians = [];

try {
  const attResp = $('GET Attendance Records').first().json;
  attendance = Array.isArray(attResp) ? attResp : (attResp.data || attResp.records || []);
} catch (e) {
  console.log('Attendance fetch failed:', e.message);
}

try {
  const techResp = $('GET Technicians').first().json;
  technicians = Array.isArray(techResp) ? techResp : (techResp.data || []);
} catch (e) {
  console.log('Technicians fetch failed:', e.message);
}

// Build lookup map
const techMap = {};
technicians.forEach(t => { techMap[t.id] = t; });

// Aggregate per technician
const stats = {};
attendance.forEach(record => {
  const tid = record.technician_id || record.worker_id || record.id;
  if (!stats[tid]) {
    stats[tid] = {
      id: tid,
      name: techMap[tid]?.name || record.technician_name || `Tech #${tid}`,
      clockIns: 0,
      clockOuts: 0,
      totalHours: 0
    };
  }
  if (record.clock_in) stats[tid].clockIns++;
  if (record.clock_out) stats[tid].clockOuts++;
  stats[tid].totalHours += record.hours_worked || record.total_hours || 0;
});

const rows = Object.values(stats).sort((a, b) => a.name.localeCompare(b.name));

// Build summary
let summary = '📋 *Weekly Attendance Report*\n\n';
if (rows.length === 0) {
  summary += 'No attendance records found for last week.';
} else {
  rows.forEach(r => {
    summary += `*${r.name}*\n`;
    summary += `  Clock-ins: ${r.clockIns} | Clock-outs: ${r.clockOuts} | Hours: ${r.totalHours.toFixed(1)}\n\n`;
  });
  summary += `Total records: ${attendance.length}`;
}

// Build CSV
const csvHeader = 'Technician,Clock-ins,Clock-outs,Total Hours\n';
const csvRows = rows.map(r => `${r.name},${r.clockIns},${r.clockOuts},${r.totalHours.toFixed(1)}`).join('\n');

return [{ json: { summary, csvContent: csvHeader + csvRows, recordCount: rows.length } }];
